changeSet.sql:
COMMENT ON TABLE organization IS 'Stores organization information for multi-tenant functionality';
COMMENT ON COLUMN organization.id IS 'Unique identifier for the organization';
COMMENT ON COLUMN organization.name IS 'Display name of the organization';
COMMENT ON COLUMN organization.slug IS 'URL-friendly unique identifier for the organization';
COMMENT ON COLUMN organization.status IS 'Current status of the organization (TRIAL, ACTIVE, SUSPENDED)';
COMMENT ON COLUMN organization.member_count IS 'Number of members in the organization';
COMMENT ON COLUMN organization.created_by IS 'User ID who created the organization';
COMMENT ON COLUMN organization.created_at IS 'Timestamp when the organization was created';
COMMENT ON COLUMN organization.deleted_by IS 'User ID who deleted the organization (soft delete)';
COMMENT ON COLUMN organization.deleted_at IS 'Timestamp when the organization was deleted (soft delete)';
COMMENT ON INDEX idx_organization_slug_unique IS 'Partial unique index for slug excluding soft-deleted organizations';
COMMENT ON INDEX idx_organization_status IS 'Index for filtering organizations by status';
COMMENT ON INDEX idx_organization_created_by IS 'Index for finding organizations by creator';
